#pragma once

#include "envoy/http/filter.h"
#include "envoy/network/connection.h"

namespace Envoy {
namespace Http {

/**
 * A minimal pass-through HTTP filter that implements StreamDecoderFilter.
 * This filter passes all data through without modification.
 */
class PassThroughFilter : public StreamDecoderFilter {
public:
  // Http::StreamFilterBase
  void onDestroy() override;

  // Http::StreamDecoderFilter
  FilterHeadersStatus decodeHeaders(RequestHeaderMap& headers, bool end_stream) override;
  FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
  FilterTrailersStatus decodeTrailers(RequestTrailerMap& trailers) override;
  void setDecoderFilterCallbacks(StreamDecoderFilterCallbacks& callbacks) override;

protected:
  StreamDecoderFilterCallbacks* decoder_callbacks_{};
};

} // namespace Http
} // namespace Envoy

